window.__deriveData = function () {
  var P = window.WINAS_PROFILE;
  var M = window.WINAS_MANGA;

  // ref date = hari ini, supaya waktu selalu relatif ke tanggal sekarang
  var REF = Date.now();
  var DAY = 86400000;
  function daysAgo(d) { var t = new Date(d).getTime(); return isNaN(t) ? 999 : Math.round((REF - t) / DAY); }
  function hueFor(s) { s = s || ""; var h = 0; for (var i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) % 360; return h; }
  function titleCaseSeries(s) { return (s || "").split(" ").map(function (w) { return w ? w[0].toUpperCase() + w.slice(1) : w; }).join(" "); }
  function relLabel(days) {
    if (days < 1) return "hari ini";
    if (days === 1) return "kemarin";
    if (days < 7) return days + " hari lalu";
    if (days < 30) return Math.floor(days / 7) + " minggu lalu";
    return Math.floor(days / 30) + " bulan lalu";
  }
  window.relTimeLabel = relLabel;

  // normalisasi: tambah field turunan yang dipakai UI
  M.forEach(function (m) {
    var nums = (m.chapters || []).map(function (c) { return c.number; });
    m.ch = nums.length ? Math.max.apply(null, nums) : (m.latestChapter || 1);
    m.updated = daysAgo(m.updatedAt);
    m.series = titleCaseSeries(m.series);
    m.hue = hueFor(m.series);
  });

  window.WINAS_DATA = {
    translator: P.translator,
    ocs: ((P.branding && P.branding.ocs) || []).map(function (o) {
      return { name: o.name, role: o.role, tags: o.personality || [], bio: o.lore, tagline: o.tagline, themeColor: o.themeColor };
    }),
    manga: M,
    updates: M.slice().sort(function (a, b) { return new Date(b.updatedAt) - new Date(a.updatedAt); }).slice(0, 6).map(function (m) {
      return { title: m.title, ch: "Ch. " + m.ch, note: (m.status === "Ongoing" ? "Update chapter" : "Rilis lengkap"), time: relLabel(m.updated), tag: m.series };
    })
  };

  window.coverFor = function (m) { return m.cover || ""; };
  // Halaman: prototype tak punya gambar asli (lokal) -> pakai dummy.
  // Produksi: bangun dari chapter.folder + nomor halaman + ekstensi (lihat handoff).
  window.pageFor = function (m, i, ch) {
    if (ch && ch.pageUrls && ch.pageUrls[i]) return ch.pageUrls[i];
    return "assets/pages/page-" + ((i % 6) + 1) + ".png"; // fallback dummy lokal
  };

  window.getDetail = function (m) {
    return Object.assign({}, m, {
      altTitle: m.series + " \u00b7 " + ((m.genres && m.genres[0]) || ""),
      artist: (m.artist && m.artist.name) || null,
      artistUrl: (m.artist && m.artist.url) || null,
      synopsis: m.description || "",
      year: null, rating: null, views: null
    });
  };

  window.getChapters = function (m) {
    var chs = (m.chapters || []).slice().sort(function (a, b) { return b.number - a.number; });
    return chs.map(function (c, idx) {
      return { n: c.number, title: null, pages: c.pages || 10, days: m.updated + idx * 7, folder: c.folder, pageUrls: c.pageUrls || [] };
    });
  };

  // progress baca (localStorage)
  function READ_KEY(t) { return "winas:read:" + t; }
  window.getReadSet = function (t) { try { return new Set(JSON.parse(localStorage.getItem(READ_KEY(t)) || "[]")); } catch (e) { return new Set(); } };
  window.getProgress = function (m) {
    var s = window.getReadSet(m.title);
    var read = [].concat.apply([], [Array.from(s)]).filter(function (n) { return n >= 1 && n <= m.ch; });
    if (!read.length) return null;
    var lastCh = Math.max.apply(null, read);
    return { lastCh: lastCh, readCount: read.length, total: m.ch, pct: Math.round(lastCh / m.ch * 100) };
  };
  window.isNew = function (m) { return m.updated <= 7; };

  // bookmarks (Pustaka)
  var BM = "winas:bookmarks";
  window.getBookmarks = function () { try { return JSON.parse(localStorage.getItem(BM) || "[]"); } catch (e) { return []; } };
  window.isBookmarked = function (t) { return window.getBookmarks().indexOf(t) >= 0; };
  window.toggleBookmark = function (t) { var l = window.getBookmarks(); var i = l.indexOf(t); if (i >= 0) l.splice(i, 1); else l.push(t); localStorage.setItem(BM, JSON.stringify(l)); return l.indexOf(t) >= 0; };

  // suara karakter (Himori ceria / Ryou cool) + sapaan acak
  window.VOICE = {
    himori: {
      name: "Himori Rinka", img: "assets/himori.png", sign: "\u2014 Himori, dengan senyum",
      greetings: [
        { title: "Halo, selamat datang! \ud83c\udf38", body: "Senang kamu mampir~ Mau baca apa hari ini? Aku sudah siapin banyak update lho! Selamat membaca yaa! (\uff61\u2022\u0300\u1d57-)\u2727" },
        { title: "Yatta, ada yang datang! \u2728", body: "Hehe, aku udah nungguin lho~ Katalognya penuh judul seru, ayo dipilih-pilih! Semangat baca!" },
        { title: "Hai hai~ apa kabar? \ud83d\udc95", body: "Semoga harimu menyenangkan yaa! Kalau bingung mau baca apa, cek 'Lanjut Baca' aja~ aku bantuin!" }
      ]
    },
    ryou: {
      name: "Ryou Akatsune", img: "assets/ryou.png", sign: "\u2014 Ryou",
      greetings: [
        { title: "Kau datang.", body: "Katalog sudah kurapikan, terjemahan sudah kuperiksa. Tidak ada yang terlewat. Silakan baca dengan tenang." },
        { title: "Selamat datang kembali.", body: "Aku sudah menyiapkan rilis terbaru. Semuanya sudah lewat pemeriksaan. Nikmati bacaanmu." },
        { title: "Akhirnya kau di sini.", body: "Tak perlu terburu-buru. Pilih judul, dan baca sesuai temponya. Aku jaga sisanya." }
      ]
    }
  };

  // seed demo (sekali) supaya Lanjut Baca / progress / Pustaka langsung terlihat (judul ASLI)
  if (!localStorage.getItem("winas:seeded2")) {
    var ong = M.filter(function (m) { return m.status === "Ongoing"; });
    ong.slice(0, 3).forEach(function (m) {
      var upTo = Math.max(1, Math.floor(m.ch * 0.6));
      var arr = []; for (var n = 1; n <= upTo; n++) arr.push(n);
      localStorage.setItem(READ_KEY(m.title), JSON.stringify(arr));
    });
    localStorage.setItem(BM, JSON.stringify(M.slice(0, 3).map(function (m) { return m.title; })));
    localStorage.setItem("winas:seeded2", "1");
  }
};

