window.DATA_READY = (function () {
  var base = (window.API_BASE || "").replace(/\/+$/, "");
  if (!base) { window.__deriveData(); return Promise.resolve(true); }
  return fetch(base + "/api/all")
    .then(function (r) {
      if (!r.ok) throw new Error("HTTP " + r.status);
      return r.json();
    })
    .then(function (data) {
      if (data.profile) window.WINAS_PROFILE = data.profile;
      var list = data.manga || [];
      // ganti isi WINAS_MANGA di tempat (in-place) agar closure tetap valid
      window.WINAS_MANGA.length = 0;
      list.forEach(function (m) { if (!m.chapters) m.chapters = []; window.WINAS_MANGA.push(m); });
      window.__deriveData();
      return true;
    })
    .catch(function (e) {
      console.error("[Winas] API gagal (" + base + "/api/all), pakai data tertanam. ", e);
      window.__deriveData();
      return false;
    });
})();
